sp_widget.client_script:
api.controller = function($scope, $element, $timeout) {
    var c = this;
    c.activeSection = 'intro';

    // 1. Setup Intersection Observer
    $timeout(function() {
        // Target the specific div that is now scrolling
        var scrollContainer = document.getElementById('policy-scroll-area');

        var observerOptions = {
            root: scrollContainer, // Crucial: Watch this specific container, not the whole window
            rootMargin: '0px 0px -60% 0px',
            threshold: 0
        };

        var observer = new IntersectionObserver(function(entries) {
            entries.forEach(function(entry) {
                if (entry.isIntersecting) {
                    $scope.$applyAsync(function() {
                        c.activeSection = entry.target.id;
                    });
                }
            });
        }, observerOptions);

        // Observe all sections
        var sections = $element[0].querySelectorAll('section[id]');
        sections.forEach(function(section) {
            observer.observe(section);
        });
    });

    // 2. Smooth scroll handler
    c.scrollTo = function(id, event) {
        if (event) event.preventDefault();

        c.activeSection = id;
        var element = document.getElementById(id);

        if (element) {
            element.scrollIntoView({ 
                behavior: 'smooth', 
                block: 'start' 
            });
        }
    };
};

sp_widget.css:
/* ===== BACK LINK ===== */
.back-link {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    color: #64748b;
    font-size: 15px;
    font-weight: 600;
    text-decoration: none;
    margin-bottom: 24px;
    transition: all 0.25s ease;
}

.back-link i {
    font-size: 14px;
    transition: transform 0.25s ease;
}

.back-link:hover {
    color: #116AF8;
}

.back-link:hover i {
    transform: translateX(-4px); /* Adds a subtle slide animation to the arrow */
}

.privacy-container {
    /* Matches your dashboard wrapper background */
    background: linear-gradient(
        to bottom right,
        #ffffff 0%,
        rgba(13, 124, 143, 0.05) 50%,
        rgba(23, 162, 184, 0.10) 100%
    );
    min-height: calc(100vh - 64px);
    padding: 30px 15%; /* Matches your dm-dashboard-wrapper padding */
    color: #1e293b;
    font-family: inherit;
}

/* Card Wrapper to emulate the table/hero cards */
.privacy-card {
    background: #ffffff;
    border-radius: 20px;
    box-shadow: 0 10px 30px rgba(10, 80, 245, 0.06);
    overflow: hidden;
    position: relative;
    max-width: 1400px;
    margin: 0 auto;
    /* Set a height so internal scrolling can activate */
    height: calc(100vh - 120px); 
    display: flex;
    flex-direction: column;
}
/* HEADER */
.policy-header {
    padding: 35px 60px;
    background-image: linear-gradient(to right, #f9fafb, #ffffff);
    border-bottom: 1px solid #f1f5f9;
    flex-shrink: 0; /* Prevents the header from shrinking */
}

.logo {
    display: flex;
    align-items: center;
    margin-bottom: 25px;
}

.tn-brand-icon svg {
    filter: drop-shadow(0 4px 10px rgba(0,0,0,0.08));
    opacity: 0.98;
}

.policy-header h1 {
    font-size: 42px;
    font-weight: 700;
    margin: 0 0 15px;
    color: #1e293b;
}

.header-description {
    max-width: 760px;
    font-size: 18px;
    line-height: 1.6;
    color: #475569;
    margin: 0;
}

/* LAYOUT */
.content-layout {
    display: flex;
    flex: 1;
    overflow: hidden; /* Traps the content so child elements handle scrolling */
}

/* SIDEBAR / TOC */
.toc-panel {
    width: 280px;
    padding: 40px;
    border-right: 1px solid #f1f5f9;
    background: #ffffff;
    /* Removed sticky positioning; allow scroll only if menu gets very long */
    overflow-y: auto; 
}

.toc-title {
    font-size: 12px;
    letter-spacing: 1.5px;
    font-weight: 700;
    color: #94a3b8;
    margin-bottom: 20px;
}

.sidebar-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.sidebar-nav li {
    margin-bottom: 6px;
}

.sidebar-nav a {
    display: block;
    text-decoration: none;
    color: #64748b;
    padding: 12px 16px;
    border-radius: 10px;
    font-size: 15px;
    font-weight: 600;
    transition: all 0.25s ease;
}

.sidebar-nav a:hover {
    background: #f8fafc;
    color: #116AF8;
}

/* Active State Match (Blue instead of Black) */
.sidebar-nav a.active {
    background: #116AF8 !important;
    color: #ffffff !important;
    box-shadow: 0 6px 15px rgba(17, 106, 248, 0.25);
}

/* MAIN CONTENT */
.policy-content {
    flex: 1;
    padding: 40px 60px;
    overflow-y: auto; /* Magic property to isolate scrolling to the right side */
    scroll-behavior: smooth;
}

.section-heading {
    display: flex;
    align-items: center;
    gap: 16px;
    margin-bottom: 25px;
}

/* Icon box matching theme blue */
.icon-box {
    width: 48px;
    height: 48px;
    border-radius: 14px;
    background: linear-gradient(135deg, #E8F1FE, #D4E4FD);
    color: #116AF8;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 20px;
}

.section-heading h2 {
    font-size: 28px;
    font-weight: 700;
    color: #1e293b;
    margin: 0;
}

.policy-content p {
    font-size: 16px;
    line-height: 1.7;
    color: #475569;
    margin-bottom: 20px;
}

section {
    margin-bottom: 70px;
    scroll-margin-top: 40px; /* Accounts for sticky offsets when scrolling */
}

/* LISTS & DATA CATEGORIES */
.data-category {
    margin-bottom: 28px;
}

.data-category h4 {
    font-size: 18px;
    font-weight: 600;
    color: #1e293b;
    margin: 0 0 8px;
}

.data-category p {
    font-size: 16px;
    color: #64748b;
    margin: 0;
}

#incident .policy-list {
    margin: 20px 0 20px 20px;
    padding: 0;
    color: #475569;
}

#incident .policy-list li {
    font-size: 16px;
    line-height: 1.7;
    margin-bottom: 8px;
}

#incident .contact-line a {
    color: #116AF8;
    font-weight: 600;
    text-decoration: none;
}

/* CONTACT SECTION */
.contact-card-container {
    margin-top: 40px;
    padding: 35px;
    border: 1px solid #f1f5f9;
    border-radius: 20px;
    background: #f8fafc;
}

.contact-description {
    margin: 15px 0 25px;
    color: #64748b;
}

.contact-grid {
    display: flex;
    gap: 20px;
    margin-bottom: 20px;
}

.contact-box {
    flex: 1;
    background: #ffffff;
    border-radius: 14px;
    padding: 20px;
    box-shadow: 0 4px 15px rgba(0,0,0,0.03);
}

.contact-label {
    font-size: 13px;
    color: #94a3b8;
    margin-bottom: 8px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.contact-box a {
    color: #0f766e; /* Using your view-all color as an accent */
    text-decoration: none;
    font-size: 16px;
    font-weight: 600;
    display: flex;
    align-items: center;
    gap: 6px;
}

.contact-address {
    color: #94a3b8;
    font-size: 14px;
}

/* FOOTER */
.policy-footer {
    margin-top: 50px;
    padding-top: 25px;
    border-top: 1px solid #f1f5f9;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.policy-version {
    color: #94a3b8;
    font-size: 14px;
}

.back-to-top {
    color: #1e293b;
    text-decoration: none;
    font-size: 14px;
    font-weight: 600;
    transition: 0.2s;
}

.back-to-top:hover {
    color: #116AF8;
}

/* RESPONSIVE */
@media(max-width: 1600px){
    .privacy-container {
        padding: 30px;
    }
}
@media(max-width: 992px){
    .content-layout { flex-direction: column; }
    .toc-panel { width: 100%; height: auto; border-right: none; border-bottom: 1px solid #f1f5f9; position: relative; padding: 30px; }
    .policy-content { padding: 40px 30px; }
    .policy-header h1 { font-size: 32px; }
    .section-heading h2 { font-size: 24px; }
}
@media(max-width: 768px){
    .contact-grid { flex-direction: column; }
}
